#include<bits/stdc++.h>
using namespace std;
long long ans=1;
int a[10005],k=1;
int main(){
    int n;
    cin>>n;
    if(n==3||n==4){
        cout<<n<<"\n";
        return 0;
    }
    for(int i=2;n;i++){
        if(n==i-1){
            a[1]=0;
            a[k]=i+1;
            for(int i=2;i<=k;i++) {cout<<a[i]<<' ';ans*=a[i];}
            cout<<"\n"<<ans;
            return 0;
        }
        if(n<i-1){
            for(int i=n,j=k-1;i>=1;i--,j--) {a[j]++;}
            for(int i=1;i<=k-1;i++) {cout<<a[i]<<' ';ans*=a[i];}
            cout<<"\n"<<ans;
            return 0;
        }
        n-=i;
        a[k++]=i;
    }
    for(int i=1;i<=k-1;i++)  {cout<<a[i]<<' ';ans*=a[i];}
    cout<<"\n"<<ans;
    return 0;
}
